/// yes_no_paired_while_active: s.status ≠ 0 ∨ s.yes_supply = s.no_supply
fn yes_no_paired_while_active(s: &State) -> bool {
    (s.status != 0) || (s.yes_supply == s.no_supply)
}

/// vault_covers_supply: s.vault ≥ s.yes_supply ∨ s.vault ≥ s.no_supply
fn vault_covers_supply(s: &State) -> bool {
    (s.vault >= s.yes_supply) || (s.vault >= s.no_supply)
}

/// status_monotone: s.status ≤ 3
fn status_monotone(s: &State) -> bool {
    s.status <= 3
}

fn initialize_market(s: &mut State, initial_collateral: u64) -> bool {
    if !(s.initialized == 0) {
        return false;
    }
    s.initialized = 1;
    s.status = 0;
    s.collateral_balance = initial_collateral;
    s.yes_supply = 0;
    s.no_supply = 0;
    s.vault = 0;
    true
}

fn split(s: &mut State, amount: u64) -> bool {
    if !(s.initialized == 1 && s.status == 0 && amount > 0 && s.collateral_balance >= amount) {
        return false;
    }
    s.collateral_balance = s.collateral_balance.wrapping_sub(amount);
    s.vault = s.vault.wrapping_add(amount);
    s.yes_supply = s.yes_supply.wrapping_add(amount);
    s.no_supply = s.no_supply.wrapping_add(amount);
    true
}

fn merge(s: &mut State, amount: u64) -> bool {
    if !(s.initialized == 1 && s.status == 0 && amount > 0 && s.yes_supply >= amount && s.no_supply >= amount && s.vault >= amount) {
        return false;
    }
    s.yes_supply = s.yes_supply.wrapping_sub(amount);
    s.no_supply = s.no_supply.wrapping_sub(amount);
    s.vault = s.vault.wrapping_sub(amount);
    s.collateral_balance = s.collateral_balance.wrapping_add(amount);
    true
}

fn resolve_yes(s: &mut State) -> bool {
    if !(s.initialized == 1 && s.status == 0) {
        return false;
    }
    s.status = 1;
    true
}

fn resolve_no(s: &mut State) -> bool {
    if !(s.initialized == 1 && s.status == 0) {
        return false;
    }
    s.status = 2;
    true
}

fn redeem_yes(s: &mut State, amount: u64) -> bool {
    if !(s.status == 1 && amount > 0 && s.yes_supply >= amount && s.vault >= amount) {
        return false;
    }
    s.yes_supply = s.yes_supply.wrapping_sub(amount);
    s.vault = s.vault.wrapping_sub(amount);
    s.collateral_balance = s.collateral_balance.wrapping_add(amount);
    true
}

fn redeem_no(s: &mut State, amount: u64) -> bool {
    if !(s.status == 2 && amount > 0 && s.no_supply >= amount && s.vault >= amount) {
        return false;
    }
    s.no_supply = s.no_supply.wrapping_sub(amount);
    s.vault = s.vault.wrapping_sub(amount);
    s.collateral_balance = s.collateral_balance.wrapping_add(amount);
    true
}

