#[derive(Debug, Clone)]
enum Op {
    InitializeMarket(u64),
    Split(u64),
    Merge(u64),
    ResolveYes,
    ResolveNo,
    RedeemYes(u64),
    RedeemNo(u64),
}

fn arb_op() -> impl Strategy<Value = Op> {
    prop_oneof![
        (0u64..=u64::MAX).prop_map(|v| Op::InitializeMarket(v)),
        (0u64..=u64::MAX).prop_map(|v| Op::Split(v)),
        (0u64..=u64::MAX).prop_map(|v| Op::Merge(v)),
        Just(Op::ResolveYes),
        Just(Op::ResolveNo),
        (0u64..=u64::MAX).prop_map(|v| Op::RedeemYes(v)),
        (0u64..=u64::MAX).prop_map(|v| Op::RedeemNo(v)),
    ]
}

fn apply_op(s: &mut State, op: &Op) -> bool {
    match op {
        Op::InitializeMarket(initial_collateral) => initialize_market(s, *initial_collateral),
        Op::Split(amount) => split(s, *amount),
        Op::Merge(amount) => merge(s, *amount),
        Op::ResolveYes => resolve_yes(s),
        Op::ResolveNo => resolve_no(s),
        Op::RedeemYes(amount) => redeem_yes(s, *amount),
        Op::RedeemNo(amount) => redeem_no(s, *amount),
    }
}

fn assert_all_properties(s: &State, context: &str) {
    assert!(yes_no_paired_while_active(s), "{} violated: yes_no_paired_while_active", context);
    assert!(vault_covers_supply(s), "{} violated: vault_covers_supply", context);
    assert!(status_monotone(s), "{} violated: status_monotone", context);
}

proptest! {
    #![proptest_config(ProptestConfig::with_cases(256))]
    #[test]
    fn state_machine_sequence(ops in proptest::collection::vec(arb_op(), 1..20)) {
        let mut s = State {
        };
        for (i, op) in ops.iter().enumerate() {
            if apply_op(&mut s, op) {
                // Check all properties after each successful transition
                prop_assert!(yes_no_paired_while_active(&s),
                    "yes_no_paired_while_active violated after op {:?} (step {})", op, i);
                prop_assert!(vault_covers_supply(&s),
                    "vault_covers_supply violated after op {:?} (step {})", op, i);
                prop_assert!(status_monotone(&s),
                    "status_monotone violated after op {:?} (step {})", op, i);
            }
        }
    }
}
